import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Create a policy for sanitizing HTML input
        PolicyFactory policy = Sanitizers.FORMATTING.and(Sanitizers.LINKS);

        // Sanitize the user input
        String sanitizedInput = policy.sanitize(userInput);

        // Safely output the sanitized input to the webpage
        System.out.println("<p>Welcome, " + sanitizedInput + "</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
